#ifndef LORA_H
#define LORA_H
void lora_setup();
void lora_loop();
bool lora_send(const uint8_t* data, size_t len);
typedef void (*lora_rx_cb)(const uint8_t* data, int len, int rssi);
void lora_on_receive(lora_rx_cb cb);
#endif

firmware_template.source:
#include "lora_block.h"
#include <SPI.h>
#include <LoRa.h>
static lora_rx_cb _rx=nullptr;
void lora_setup(){
  LoRa.setPins(5,14,2);
  if(!LoRa.begin(915E6)){Serial.println("[lora] Init failed!");return;}
  LoRa.setSpreadingFactor(7);LoRa.setSignalBandwidth(125E3);
  Serial.println("[lora] OK 915MHz");
}
void lora_loop(){
  int sz=LoRa.parsePacket();
  if(sz>0&&_rx){
    uint8_t buf[256];int i=0;
    while(LoRa.available()&&i<256)buf[i++]=LoRa.read();
    _rx(buf,i,LoRa.packetRssi());
  }
}
bool lora_send(const uint8_t*d,size_t l){LoRa.beginPacket();LoRa.write(d,l);return LoRa.endPacket();}
void lora_on_receive(lora_rx_cb cb){_rx=cb;}
